def subset_sum(xs, target):
    n = len(xs)
    dp = [False] * (target + 1)
    dp[0] = True  # Base case: zero sum is always possible with an empty subset

    for num in xs:
        for t in range(target, num - 1, -1):
            dp[t] = dp[t] or dp[t - num]

    return dp[target]
